sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;

    c.refresh = function() {
        if (c.loading) return;
        c.loading = true;
        c.server.get({ action: 'refresh' }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.loading = false;
        });
    };
};

sp_widget.css:
.sp-college-dashboard .page-header {
    border-bottom: 1px solid $border-tertiary;
    margin-bottom: 24px;
    padding-bottom: 16px;
}
.sp-college-dashboard .page-header h2 {
    color: $text-color;
    font-weight: 600;
    margin-top: 0;
}
.sp-college-dashboard .page-header .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}

/* Stat Tiles */
.sp-college-dashboard .sp-stat-tile {
    display: flex;
    align-items: center;
    padding: 20px;
    margin-bottom: 24px;
    border-radius: 4px;
    background: $background-primary;
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
}
.sp-college-dashboard .sp-stat-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 16px;
    font-size: 20px;
}
.sp-college-dashboard .sp-stat-info .sp-stat-icon {
    background: $state-info-bg;
    color: $brand-info;
}
.sp-college-dashboard .sp-stat-success .sp-stat-icon {
    background: $state-success-bg;
    color: $brand-success;
}
.sp-college-dashboard .sp-stat-warning .sp-stat-icon {
    background: $state-warning-bg;
    color: $brand-warning;
}
.sp-college-dashboard .sp-stat-danger .sp-stat-icon {
    background: $state-danger-bg;
    color: $brand-danger;
}
.sp-college-dashboard .sp-stat-content {
    flex: 1;
}
.sp-college-dashboard .sp-stat-value {
    font-size: 28px;
    font-weight: 700;
    color: $text-color;
    line-height: 1.2;
}
.sp-college-dashboard .sp-stat-label {
    font-size: 13px;
    color: $text-muted;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Panel */
.sp-college-dashboard .sp-panel {
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    margin-bottom: 24px;
}
.sp-college-dashboard .sp-panel .panel-heading {
    background: $background-secondary;
    border-bottom: 1px solid $border-tertiary;
}
.sp-college-dashboard .sp-panel .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-college-dashboard .sp-panel .panel-title .badge {
    background: $brand-warning;
    color: $background-primary;
    margin-left: 8px;
}
.sp-college-dashboard .sp-panel .table th {
    color: $text-muted;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid $border-tertiary;
}
.sp-college-dashboard .sp-panel .table td {
    vertical-align: middle;
    color: $text-color;
}

sp_widget.script:
(function() {
    data.totalClubs = 0;
    data.activeClubs = 0;
    data.pendingClubs = 0;
    data.totalEvents = 0;
    data.liveEvents = 0;
    data.totalRegistrations = 0;
    data.totalStudents = 0;
    data.recentClubs = [];
    data.recentEvents = [];
    data.message = '';
    data.isCollegeAdmin = false;
    data.collegeName = '';

    try {
        if (input && input.action === 'refresh') {
            // Same logic as initial load — allows client refresh
        }

        var userId = gs.getUserID();

        // Get the current user's college
        var userGr = new GlideRecord('sys_user');
        userGr.setLimit(1);
        if (!userGr.get(userId)) {
            data.message = 'Unable to identify current user.';
            return;
        }

        var collegeId = userGr.getValue('u_college') + '';
        if (!collegeId || collegeId === 'null' || collegeId === '') {
            data.message = 'You are not assigned to a college.';
            return;
        }

        data.isCollegeAdmin = true;
        data.collegeName = userGr.getDisplayValue('u_college') + '';

        // Total clubs in this college
        var clubGr = new GlideRecord('x_2097092_linq_club');
        clubGr.addQuery('college', collegeId);
        clubGr.setLimit(1000);
        clubGr.query();

        var clubIds = [];
        while (clubGr.next()) {
            clubIds.push(clubGr.getUniqueValue());
            data.totalClubs++;

            var clubStatus = clubGr.getValue('status') + '';
            if (clubStatus === 'active') {
                data.activeClubs++;
            } else if (clubStatus === 'pending_approval') {
                data.pendingClubs++;
            }
        }

        // Total events for clubs in this college
        var eventIds = [];
        if (clubIds.length > 0) {
            var evGr = new GlideRecord('x_2097092_linq_event');
            evGr.addQuery('college', collegeId);
            evGr.setLimit(1000);
            evGr.query();

            while (evGr.next()) {
                eventIds.push(evGr.getUniqueValue());
                data.totalEvents++;

                if (evGr.getValue('status') + '' === 'live') {
                    data.liveEvents++;
                }
            }
        }

        // Total registrations
        if (eventIds.length > 0) {
            var regGa = new GlideAggregate('x_2097092_linq_registration');
            regGa.addQuery('event', 'IN', eventIds.join(','));
            regGa.addAggregate('COUNT');
            regGa.query();
            if (regGa.next()) {
                data.totalRegistrations = parseInt(regGa.getAggregate('COUNT'), 10) || 0;
            }
        }

        // Total students (unique members across all clubs in college)
        if (clubIds.length > 0) {
            var memGa = new GlideAggregate('x_2097092_linq_club_membership');
            memGa.addQuery('club', 'IN', clubIds.join(','));
            memGa.addQuery('status', 'active');
            memGa.addAggregate('COUNT', 'member');
            memGa.groupBy('member');
            memGa.setLimit(5000);
            memGa.query();

            var uniqueMembers = 0;
            while (memGa.next()) {
                uniqueMembers++;
            }
            data.totalStudents = uniqueMembers;
        }

        // Recent clubs submitted for approval (last 5)
        var recentClubGr = new GlideRecord('x_2097092_linq_club');
        recentClubGr.addQuery('college', collegeId);
        recentClubGr.addQuery('status', 'pending_approval');
        recentClubGr.orderByDesc('sys_created_on');
        recentClubGr.setLimit(5);
        recentClubGr.query();

        while (recentClubGr.next()) {
            data.recentClubs.push({
                sys_id: recentClubGr.getUniqueValue(),
                name: recentClubGr.getValue('name') + '',
                created_by: recentClubGr.getDisplayValue('created_by') + '',
                date_submitted: recentClubGr.getDisplayValue('sys_created_on') + ''
            });
        }

        // Recent events submitted for approval (last 5)
        var recentEvGr = new GlideRecord('x_2097092_linq_event');
        recentEvGr.addQuery('college', collegeId);
        recentEvGr.addQuery('status', 'submitted');
        recentEvGr.orderByDesc('sys_created_on');
        recentEvGr.setLimit(5);
        recentEvGr.query();

        while (recentEvGr.next()) {
            data.recentEvents.push({
                sys_id: recentEvGr.getUniqueValue(),
                title: recentEvGr.getValue('title') + '',
                club_name: recentEvGr.getDisplayValue('club') + '',
                date_submitted: recentEvGr.getDisplayValue('sys_created_on') + ''
            });
        }
    } catch (e) {
        gs.error('linq-admin-college-dashboard error: ' + e.message);
        data.message = 'An error occurred loading dashboard data.';
    }
})();
